/* Test driver */
public class Main {
    public static void main(String[] args) {
        ConnectionPool pool = new ConnectionPool(new PoolConfig(2, 5, 1000));
        Connection c = pool.borrow();
        System.out.println("OK_BORROW=" + (c != null) + " ACTIVE=" + pool.getStats().getActive() + " TOTAL=" + pool.getStats().getTotal());
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        ConnectionPool pool = new ConnectionPool(new PoolConfig(1, 3, 1000));
        Connection c1 = pool.borrow();
        String id1 = c1.getId();
        pool.returnConnection(c1);
        Connection c2 = pool.borrow();
        System.out.println("OK_REUSE=" + id1.equals(c2.getId()) + " ACTIVE=" + pool.getStats().getActive());
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        ConnectionPool pool = new ConnectionPool(new PoolConfig(0, 1, 200));
        pool.borrow();
        try { pool.borrow(); System.out.println("WRONG"); } catch (RuntimeException e) { System.out.println("OK_EXHAUSTED:" + e.getMessage()); }
        pool.shutdown();
        try { pool.borrow(); System.out.println("WRONG2"); } catch (IllegalStateException e) { System.out.println("OK_SHUTDOWN:" + e.getMessage()); }
    }
}
